struct Node {
    int data;
    Node* next;
    Node(int d) : data(d), next(nullptr) {}
};

void insertAtEnd(Node*& head, int val) {
    Node* newNode = new Node(val);
    if (!head) {
        head = newNode;
        return;
    }
    Node* curr = head;
    while (curr->next) curr = curr->next;
    curr->next = newNode;
}

int main() {
    Node* head = nullptr;
    insertAtEnd(head, 10);
    insertAtEnd(head, 20);
    insertAtEnd(head, 30);
    // Output: 10 20 30
    return 0;
}

#include <iostream>
using namespace std;

struct Node {
    int data;
    Node* next;
    Node(int d) : data(d), next(nullptr) {}
};

void insertAtPosition(Node*& head, int val, int pos) {
    if (pos < 0) return;
    Node* newNode = new Node(val);
    if (pos == 0) {
        newNode->next = head;
        head = newNode;
        return;
    }
    Node* curr = head;
    for (int i = 0; i < pos - 1 && curr; i++) {
        curr = curr->next;
    }
    if (!curr) { delete newNode; return; } // position out of range
    newNode->next = curr->next;
    curr->next = newNode;
}

int main() {
    Node* head = nullptr;
    insertAtEnd(head, 10); insertAtEnd(head, 30);
    insertAtPosition(head, 20, 1); // 10 20 30
    return 0;
}

