struct Node {
    int data;
    Node* next;
    Node(int d) : data(d), next(nullptr) {}
};

void deleteByValue(Node*& head, int val) {
    if (!head) return;
    if (head->data == val) {
        Node* temp = head;
        head = head->next;
        delete temp;
        return;
    }
    Node* curr = head;
    while (curr->next && curr->next->data != val) {
        curr = curr->next;
    }
    if (curr->next) {
        Node* temp = curr->next;
        curr->next = temp->next;
        delete temp;
    }
}

int main() {
    Node* head = nullptr;
    insertAtEnd(head, 10); insertAtEnd(head, 20); insertAtEnd(head, 30);
    deleteByValue(head, 20);
    // List: 10 30
    return 0;
}

