struct Node {
    int data;
    Node* next;
    Node(int d) : data(d), next(nullptr) {}
};

void deleteAtPosition(Node*& head, int pos) {
    if (!head || pos < 0) return;
    if (pos == 0) {
        Node* temp = head;
        head = head->next;
        delete temp;
        return;
    }
    Node* curr = head;
    for (int i = 0; i < pos - 1 && curr; i++) curr = curr->next;
    if (!curr || !curr->next) return;
    Node* temp = curr->next;
    curr->next = temp->next;
    delete temp;
}

int main() {
    Node* head = nullptr;
    insertAtEnd(head, 10); insertAtEnd(head, 20); insertAtEnd(head, 30);
    deleteAtPosition(head, 1); // removes 20
    return 0;
}

