struct Node {
    int data;
    Node* next;
    Node(int d) : data(d), next(nullptr) {}
};

Node* reverse(Node* head) {
    Node* prev = nullptr;
    Node* curr = head;
    Node* next = nullptr;
    while (curr) {
        next = curr->next;
        curr->next = prev;
        prev = curr;
        curr = next;
    }
    return prev;
}

void print(Node* head) {
    while (head) { cout << head->data << " "; head = head->next; }
    cout << endl;
}

int main() {
    Node* head = nullptr;
    insertAtEnd(head, 1); insertAtEnd(head, 2); insertAtEnd(head, 3);
    print(head);        // 1 2 3
    head = reverse(head);
    print(head);        // 3 2 1
    return 0;
}

